#include <iostream>
#include <vector>
using namespace std;

vector<int> solve(vector<int>& nums) {
    int n=nums.size();
    vector<int> res(n,1);
    int pre=1;
    for(int i=0;i<n;i++){res[i]=pre;pre*=nums[i];}
    int suf=1;
    for(int i=n-1;i>=0;i--){res[i]*=suf;suf*=nums[i];}
    return res;
}

int main(){
    int v; vector<int> arr;
    while(cin>>v) arr.push_back(v);
    auto res=solve(arr);
    for(int i=0;i<res.size();i++){if(i)cout<<' ';cout<<res[i];}
    cout<<endl; return 0;
}

